db_schema:
export type SyncStatus = "pending" | "synced" | "error";

export interface OnboardingProfile {
  id: string;
  goal: "strength" | "diet" | "maintain";
  heightCm: number;
  weightKg: number;
  createdAt: string;
  updatedAt: string;
  syncStatus: SyncStatus;
}

export interface WorkoutSession {
  id: string;
  startedAt: string;
  date: string;
  endedAt?: string;
  isCompleted: boolean;
  totalVolumeKg?: number;
  totalDurationSec?: number;
  createdAt: string;
  updatedAt: string;
  syncStatus: SyncStatus;
}

export interface ExerciseEntry {
  id: string;
  sessionId: string;
  name: string;
  category?: string;
  type: "weight" | "cardio";
  order: number;
  note?: string;
  createdAt: string;
  updatedAt: string;
  syncStatus: SyncStatus;
}

export interface SetEntry {
  id: string;
  exerciseId: string;
  setNumber: number;
  weightKg: number;
  reps: number;
  restPlannedSec: number;
  completedAt?: string;
  createdAt: string;
  updatedAt: string;
  syncStatus: SyncStatus;
}

export interface CardioEntry {
  id: string;
  exerciseId: string;
  durationSec: number;
  distanceKm?: number;
  createdAt: string;
  updatedAt: string;
  syncStatus: SyncStatus;
}

export interface SyncQueueItem {
  id: string;
  createdAt: string;
  attemptCount: number;
  status: "pending" | "error";
  method: "POST" | "PATCH" | "DELETE";
  path: string;
  body: unknown | null;
  entityType: string;
  entityId: string;
  lastError?: string;
}
